import { Component, Input, Output, EventEmitter } from '@angular/core';

@Component({
  selector: 'app-info-alert',
  templateUrl: './info-alert.component.html',
  styleUrls: ['./info-alert.component.css']
})
export class InfoAlertComponent {
  @Input()
  styleToInsert: string = "";

  @Input()
  styleToInsert2: string = "";

  @Input()
  message: string = "";

  @Output()
  statusCode = new EventEmitter<null>();

  onClose(): void {
    this.statusCode.emit(null);
  }
}
<div class="p-3 bg-dark bg-gradient border border-3 rounded-3" [ngClass]="styleToInsert2">
    <div class="row">
        <div class="pb-2" [ngClass]="styleToInsert">Information</div>
        <hr class="separator m-auto rounded"/>
        <div class="text-start py-3">{{message}}</div>
        <button class="btn-close btn-close-white position-absolute top-0 end-0 me-2 mt-2" (click)="onClose()"></button>
    </div>
</div>
